// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UxExecutionRun) predicate.UxExecutionRun {
	return predicate.UxExecutionRun(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UxExecutionRun) predicate.UxExecutionRun {
	return predicate.UxExecutionRun(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UxExecutionRun) predicate.UxExecutionRun {
	return predicate.UxExecutionRun(sql.NotPredicates(p))
}
